list limits failed.');putenv('SF_ENV=production');putenv('SF_MEDIA_SIGNING_KEY=short');$assert(sf_revenue_media_signing_ready()===false,'Production signing must reject short secrets.');if($failures){foreach($failures as$f)fwrite(STDERR,"FAIL: {$f}\n");exit(1);}echo"Revenue, membership, and media access smoke tests passed.\n";
